code.C:
int findMaxConsecutiveOnes(int nums[], int n) {
    int count = 0;
    int maxCount = 0;

    for (int i = 0; i < n; i++) {
        if (nums[i] == 1) {
            count++;
            if (count > maxCount) {
                maxCount = count;
            }
        } else {
            count = 0;
        }
    }

    return maxCount;
}

code.Java:
public static int findMaxConsecutiveOnes(int[] nums) {
    int count = 0;     // current streak
    int maxCount = 0;  // maximum streak

    for (int num : nums) {
        if (num == 1) {
            count++;
            maxCount = Math.max(maxCount, count);
        } else {
            count = 0;
        }
    }
    return maxCount;
}

